    // at androidx.compose.compiler.plugins.kotlin.lower.decoys.DecoyTransformBase$DefaultImpls.getComposableForDecoy(DecoyTransformBase.kt:110)
    fun testLocalClassWithComposable() = runTest {
        val root = composeText {
