@Composable
@ExperimentalComposeWebSvgApi
fun Svg(
  viewBox: String? = null,
  attrs: AttrBuilderContext<SVGElement>? = null,
  content: ContentBuilder<SVGElement>? = null
) {
    TagElement(
        elementBuilder = Svg,
        applyAttrs = {
            viewBox?.let { viewBox(it) }
            attrs?.invoke(this)
        },
        content = content
    )
}

